// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   // in this scenario, set it when loading
	//if (isLoading || newValue === '') {
	if (newValue === '') {
      return;
   }

	//STRY0075793 - when template changes, load the fields based on the template and top task, provided
	if(newValue){
		var fields = '';
		var tCTH = new GlideAjax('ClientTaskTemplateHelpers');
		var templateId = g_form.getValue('routing_template_ref') + '';
		var parentTaskId = g_form.getValue('parent_task') + '';
		if(templateId != ''){
			if(parentTaskId != ''){
				tCTH.addParam('sysparm_name','loadTemplateAndTaskIntoInstanceForm');
				tCTH.addParam("fields", fields);
				tCTH.addParam("templateId", templateId);
				tCTH.addParam("parentTaskId", parentTaskId);
				// call script include to get the default fields
				tCTH.getXML(f_returnLoadTemplateInstanceForm);

			// no task information, just load from template
			} else {
				tCTH.addParam('sysparm_name','loadTemplateIntoInstanceForm');
				tCTH.addParam("fields", fields);
				tCTH.addParam("templateId", templateId);
				// call script include to get the default fields
				tCTH.getXML(f_returnLoadTemplateInstanceForm);

			}
		}
	}

}

function f_returnLoadTemplateInstanceForm(response)
{
	var answer = response.responseXML.documentElement.getAttribute("answer");
	var fields = JSON.parse(answer);
	for(var field in fields){
		if(field != 'routing_template_ref'){
			if (field == 'u_template_subtask_s_name_setting'){
				g_scratchpad.u_template_subtask_s_name_setting = fields[field].value == null ? '' : fields[field].value;
				var subtaskSettingIsNone = (g_scratchpad.u_template_subtask_s_name_setting == '' || g_scratchpad.u_template_subtask_s_name_setting == 'None');
				g_form.setMandatory('u_subtask_s_name_modifier', !subtaskSettingIsNone);
				g_form.setDisplay('u_subtask_s_name_modifier', !subtaskSettingIsNone);
				if(!subtaskSettingIsNone){
					if(fields[field].value == 'prefix'){
						g_form.showFieldMsg('u_subtask_s_name_modifier', getMessage('Tasker - The value entered will apply as a Prefix to the Task Name of all Subtasks'), 'info');
					} else if(fields[field].value == 'suffix'){
						g_form.showFieldMsg('u_subtask_s_name_modifier', getMessage('Tasker - The value entered will apply as a Suffix to the Task Name of all Subtasks'), 'info');
					}

				} else{
					g_form.hideAllFieldMsgs('u_subtask_s_name_modifier');
				}
			// u_template_subtask_s_name_setting is not on the form, don't try to set it
			} else if(fields[field].value){
				g_form.setValue(field,fields[field].value);
			}
		}
	}
	var templateId = g_form.getValue('routing_template_ref') + '';
	var tCTH2 = new GlideAjax('ClientTaskTemplateHelpers');
	tCTH2.addParam('sysparm_name','getTemplateTopTaskerType');
	tCTH2.addParam("templateId", templateId);
	// call script include to get the default fields
	tCTH2.getXML(f_returnGetTemplateTopTaskerType);
}

function f_returnGetTemplateTopTaskerType(response)	{
	var acknowledgement = 'Acknowledgement';
	var information_only = 'Information Only';
	var Approval_with_signature = 'Approval with signature';
	var Concur_with_signature = 'Concur with signature';

	var tasker_type = response.responseXML.documentElement.getAttribute("answer");

	if(tasker_type ==  acknowledgement|| tasker_type == information_only){
		g_form.setDisplay("u_reviewer", false);
	}else{
		g_form.setDisplay("u_reviewer", true);
	}
}
